<template><main v-if='dish' class='cook'><button class='close' @click='$router.back()'>完成</button><header><span class='badge'>做菜模式</span><h1>{{dish.name}}</h1><p>第 {{current+1}} / {{dish.steps.length}} 步 · {{step.duration}}</p></header><section class='panel card'><img :src='step.image'/><div class='progress'><i :style='{width:`${((current+1)/dish.steps.length)*100}%`}'></i></div><h2>{{step.title}}</h2><p>{{step.text}}</p><b>关键提示：{{step.tip}}</b></section><footer class='safe-bottom'><button class='secondary-button' :disabled='current===0' @click='current--'>上一步</button><button class='ios-button' @click='next'>{{current===dish.steps.length-1?'完成':'下一步'}}</button></footer></main></template><script setup>import{computed,onMounted,ref}from'vue';import{useRoute,useRouter}from'vue-router';import{useRecipes}from'../composables/useRecipes';const route=useRoute(),router=useRouter();const{dishes,loadRecipes}=useRecipes();const current=ref(0);onMounted(loadRecipes);const dish=computed(()=>dishes.value.find(x=>x.id===Number(route.params.id)));const step=computed(()=>dish.value?.steps?.[current.value]||{});function next(){if(current.value<dish.value.steps.length-1)current.value++;else router.back()}</script><style scoped>.cook{min-height:100vh;background:var(--bg);padding:26px 16px 120px}.close{position:fixed;right:18px;top:18px;border:0;border-radius:999px;background:rgba(255,255,255,.85);padding:10px 16px;font-weight:900;color:var(--blue);z-index:5}header{padding-top:34px}h1{margin:12px 0 6px;font-size:32px}.cook header p{margin:0;color:var(--sub)}.panel{margin-top:20px;padding:16px}.panel img{width:100%;height:260px;border-radius:22px;object-fit:cover;background:#eee}.progress{height:8px;border-radius:999px;background:#f2f2f7;margin:16px 0;overflow:hidden}.progress i{display:block;height:100%;border-radius:999px;background:var(--blue);transition:.3s}h2{margin:0;font-size:24px}.panel p{font-size:18px;line-height:1.7;color:#333}.panel b{display:block;padding:14px;border-radius:18px;background:#fff8e8;color:#b36b00;font-size:14px;line-height:1.5}footer{position:fixed;left:50%;bottom:0;transform:translateX(-50%);width:min(100%,430px);display:grid;grid-template-columns:1fr 1fr;gap:10px;padding:14px 16px 28px;background:rgba(255,255,255,.82);border-top:1px solid rgba(0,0,0,.06)}button:disabled{opacity:.45}</style>
